const text = $input.first().json.content.parts[0].text;
// Remove potential markdown code blocks
const cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const data = JSON.parse(cleanText);

// 나레이션 글자수 검증 (200자 초과 시 잘라내기)
let narration = data.Narration || '';
if (narration.length > 200) {
  // 200자 근처에서 문장 끝(마침표/물음표/느낌표)에서 자르기
  const cutPoint = narration.substring(0, 200).lastIndexOf('.');
  const cutQ = narration.substring(0, 200).lastIndexOf('?');
  const cutE = narration.substring(0, 200).lastIndexOf('!');
  const bestCut = Math.max(cutPoint, cutQ, cutE);
  if (bestCut > 100) {
    narration = narration.substring(0, bestCut + 1);
  } else {
    narration = narration.substring(0, 200);
  }
}

return [{
  json: {
    Subject: data.Subject,
    Narration: narration,
    Caption: data.Caption,
    Comment: data.Comment,
    BGM_prompt: data.BGM_prompt,
    Status: '준비',
    Publish: '대기중',
    generatedAt: new Date().toISOString()
  }
}];

// 나레이션을 코드로 직접 5파트 균등 분할 (누적 글자수 알고리즘)
const narration = $('주제 파싱').first().json.Narration;
if (!narration) throw new Error('나레이션이 비어있습니다');

// Step 1: 문장 분리 (. ! ? 기준)
let chunks = narration.split(/(?<=[.!?])\s*/).filter(s => s.trim().length > 0);
console.log(`문장 수: ${chunks.length}, 전체 길이: ${narration.length}자`);

// Step 2: 5개 미만이면 가장 긴 청크를 쉼표/공백에서 분할
while (chunks.length < 5) {
    let longestIdx = 0;
    for (let i = 1; i < chunks.length; i++) {
        if (chunks[i].length > chunks[longestIdx].length) longestIdx = i;
    }
    const longest = chunks[longestIdx];
    const mid = Math.floor(longest.length / 2);
    let splitPos = -1;

    // 중간 근처 쉼표 찾기
    for (let off = 0; off <= mid && splitPos < 0; off++) {
        if (mid + off < longest.length && longest[mid + off] === ',') splitPos = mid + off + 1;
        else if (mid - off >= 0 && longest[mid - off] === ',') splitPos = mid - off + 1;
    }
    // 쉼표 없으면 공백에서
    if (splitPos < 0) {
        for (let off = 0; off <= mid && splitPos < 0; off++) {
            if (mid + off < longest.length && longest[mid + off] === ' ') splitPos = mid + off;
            else if (mid - off >= 0 && longest[mid - off] === ' ') splitPos = mid - off;
        }
    }

    if (splitPos > 0 && splitPos < longest.length - 1) {
        const a = longest.substring(0, splitPos).trim();
        const b = longest.substring(splitPos).trim();
        if (a.length > 0 && b.length > 0) {
            chunks.splice(longestIdx, 1, a, b);
        } else break;
    } else break;
}
console.log(`분할 후 청크 수: ${chunks.length}`);

// Step 3: 누적 글자수 기반으로 최적의 5등분 지점 찾기
const cumLen = [0];
for (const c of chunks) cumLen.push(cumLen[cumLen.length - 1] + c.length);
const total = cumLen[cumLen.length - 1];
const target = total / 5;

const cuts = [0];
for (let p = 1; p <= 4; p++) {
    const ideal = target * p;
    const minJ = cuts[cuts.length - 1] + 1;
    const maxJ = chunks.length - (5 - p);
    let bestJ = minJ;
    let bestDiff = Infinity;
    for (let j = minJ; j <= maxJ; j++) {
        const diff = Math.abs(cumLen[j] - ideal);
        if (diff < bestDiff) { bestDiff = diff; bestJ = j; }
    }
    cuts.push(bestJ);
}
cuts.push(chunks.length);

// 5파트 구성
const parts = [];
for (let p = 0; p < 5; p++) {
    parts.push(chunks.slice(cuts[p], cuts[p + 1]).join(' ').trim());
}

// 자막 자동 생성: 첫 문장 + 최대 25자 + 2줄 분리
function makeSubtitle(fullText) {
    if (!fullText) return '';
    const sents = fullText.split(/(?<=[.!?])\s*/).filter(s => s.trim().length > 0);
    let core = (sents[0] || fullText).trim();
    if (core.length <= 15) return core;
    if (core.length > 25) {
        let cutIdx = 25;
        for (let i = 25; i >= 15; i--) {
            if (core[i] === ' ' || core[i] === ',') { cutIdx = i; break; }
        }
        core = core.substring(0, cutIdx).trim().replace(/[,\s]+$/, '');
    }
    const mid = Math.floor(core.length / 2);
    let splitIdx = -1;
    for (let off = 0; off <= mid; off++) {
        const fwd = mid + off;
        const bwd = mid - off;
        if (fwd < core.length && core[fwd] === ' ') { splitIdx = fwd; break; }
        if (bwd >= 0 && core[bwd] === ' ') { splitIdx = bwd; break; }
    }
    if (splitIdx === -1 || core.length <= 18) return core;
    return core.substring(0, splitIdx).trim() + '\\N' + core.substring(splitIdx).trim();
}

// 출력
const items = [];
for (let i = 0; i < parts.length; i++) {
    const text = parts[i].trim();
    if (text.length > 0) {
        const sub = makeSubtitle(text);
        items.push({
            json: {
                text: text,
                subtitle: sub,
                index: i + 1,
                subject: $('주제 파싱').first().json.Subject,
                bgmPrompt: $('주제 파싱').first().json.BGM_prompt,
                narration: narration
            }
        });
        console.log(`Part ${i+1} (${text.length}자): "${text.substring(0,50)}..." subtitle="${sub}"`);
    }
}

if (items.length === 0) throw new Error('나레이션 분할 결과가 비어있습니다');
console.log(`총 ${items.length}파트, 파트별 길이: [${items.map(it => it.json.text.length + '자').join(', ')}]`);
return items;

