const text = $input.first().json.content.parts[0].text;
const cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const data = JSON.parse(cleanText);

let narration = data.Narration || '';
if (narration.length > 150) {
  const cutPoint = narration.substring(0, 150).lastIndexOf('.');
  if (cutPoint > 80) {
    narration = narration.substring(0, cutPoint + 1);
  } else {
    narration = narration.substring(0, 150);
  }
}

return [{
  json: {
    Subject: data.Subject,
    Narration: narration,
    Caption: data.Caption,
    Comment: data.Comment,
    BGM_prompt: data.BGM_prompt,
    Status: '준비',
    Publish: '',
    generatedAt: new Date().toISOString()
  }
}];

// NCA 영상 제작 - BGM 루프 + 슬로우/루프/5초단위 장면분할 + 자막 + 아웃트로
const firstItem = $input.first().json;
const dataArray = firstItem.data || [];

const narrations = [];
const videos = [];
let bgmUrl = '';

for (const item of dataArray) {
    if (item.video && item.video.url) {
        videos.push(item.video.url);
    } else if (item.audio && item.audio.url) {
        if (item.metadata && item.metadata.duration) {
            bgmUrl = item.audio.url;
        } else {
            const fileSize = item.audio.file_size || 0;
            const estimatedDuration = Math.max(Math.round((fileSize * 8 / 128000) * 100) / 100, 3);
            narrations.push({
                url: item.audio.url,
                duration: estimatedDuration + 2,
            });
        }
    }
}

// 자막 텍스트 가져오기
let subtitleTexts = [];
let fullNarrationTexts = [];
try {
    const partItems = $('5파트 분리').all();
    subtitleTexts = partItems.map(item => item.json.subtitle || item.json.text || '');
    fullNarrationTexts = partItems.map(item => item.json.text || '');
} catch (e) {
    console.log('Could not get subtitles:', e.message);
}

// 2줄 분리 헬퍼
function splitToTwoLines(text) {
    if (!text || text.length <= 16) return text || '';
    const mid = Math.floor(text.length / 2);
    let splitIdx = -1;
    for (let offset = 0; offset <= mid; offset++) {
        const fwd = mid + offset;
        const bwd = mid - offset;
        if (fwd < text.length && text[fwd] === ' ') { splitIdx = fwd; break; }
        if (bwd >= 0 && text[bwd] === ' ') { splitIdx = bwd; break; }
    }
    if (splitIdx === -1) return text;
    return text.substring(0, splitIdx).trim() + '\\N' + text.substring(splitIdx).trim();
}

// 나레이션 텍스트를 N개 세그먼트로 분할 (요약 없이 전체)
function splitNarrationText(fullText, segCount) {
    if (segCount <= 1) return [fullText];
    const sentences = fullText.split(/(?<=[.!?])\s*/).filter(s => s.trim().length > 0);

    if (sentences.length >= segCount) {
        const result = [];
        const perSeg = Math.floor(sentences.length / segCount);
        let idx = 0;
        for (let s = 0; s < segCount; s++) {
            const end = (s === segCount - 1) ? sentences.length : idx + perSeg;
            result.push(sentences.slice(idx, end).join(' ').trim());
            idx = end;
        }
        return result;
    } else {
        const charPerSeg = Math.ceil(fullText.length / segCount);
        const result = [];
        let remaining = fullText;
        for (let s = 0; s < segCount - 1; s++) {
            let cutPos = Math.min(charPerSeg, remaining.length);
            for (let j = cutPos; j >= cutPos - 10 && j >= 1; j--) {
                if (remaining[j] === ' ' || remaining[j] === ',') { cutPos = j; break; }
            }
            result.push(remaining.substring(0, cutPos).trim());
            remaining = remaining.substring(cutPos).trim();
        }
        result.push(remaining.trim());
        return result;
    }
}

const partCount = Math.min(narrations.length, videos.length, 5);
const SCENE_DURATION = 5;      // 영상 기본 길이 (5초)
const MAX_SLOW_SECONDS = 6.5;  // 6.5초까지 슬로우, 이상이면 루프
const SPLIT_SECONDS = 8;       // 8초 이상이면 장면 분할
const OUTRO_URL = 'http://76.13.182.180:9000/nca-toolkit/assets/outro_lumix.mp4';
const OUTRO_DURATION = 5;

console.log('Parts:', partCount, 'Videos:', videos.length, 'Narrations:', narrations.length, 'BGM:', bgmUrl ? 'YES' : 'NO');

// === 세그먼트 구성 (5초 단위 분할, 나머지 < 5초면 5초로) ===
const segments = [];
for (let i = 0; i < partCount; i++) {
    const dur = narrations[i].duration;
    const videoUrl = videos[i];
    const audioUrl = narrations[i].url;
    const subText = subtitleTexts[i] || '';
    const fullText = fullNarrationTexts[i] || '';

    if (dur >= SPLIT_SECONDS) {
        // 8초 이상: 5초 단위로 분할
        const sceneDurations = [];
        let remaining = dur;
        while (remaining >= SPLIT_SECONDS) {
            sceneDurations.push(SCENE_DURATION);
            remaining = Math.round((remaining - SCENE_DURATION) * 100) / 100;
        }
        // 나머지: 5초 미만이면 5초로 (영상 길이에 맞춤), 아니면 그대로
        const lastDur = remaining < SCENE_DURATION ? SCENE_DURATION : remaining;
        sceneDurations.push(lastDur);

        // 나레이션 텍스트를 세그먼트 수만큼 분할 (요약 없이)
        const textParts = splitNarrationText(fullText, sceneDurations.length);

        // 오디오 구간 계산 (실제 나레이션 길이 기준)
        const audioDurations = [];
        let audioRemaining = dur;
        for (let s = 0; s < sceneDurations.length - 1; s++) {
            audioDurations.push(SCENE_DURATION);
            audioRemaining = Math.round((audioRemaining - SCENE_DURATION) * 100) / 100;
        }
        audioDurations.push(audioRemaining); // 마지막은 실제 남은 오디오 길이

        let audioOffset = 0;
        for (let s = 0; s < sceneDurations.length; s++) {
            segments.push({
                videoUrl, audioUrl,
                sceneDuration: sceneDurations[s],   // 장면 길이 (영상 기준)
                audioDuration: audioDurations[s],    // 실제 오디오 길이
                audioStart: audioOffset,
                needsPad: sceneDurations[s] > audioDurations[s], // 오디오 패딩 필요
                subtitleText: splitToTwoLines(textParts[s] || ''),
                type: 'split', splitIndex: s
            });
            audioOffset = Math.round((audioOffset + audioDurations[s]) * 100) / 100;
        }
        console.log(`Part ${i+1}: dur=${dur.toFixed(1)}s, SPLIT -> [${sceneDurations.map(d => d.toFixed(1)+'s').join(', ')}] (audio: [${audioDurations.map(d => d.toFixed(1)+'s').join(', ')}])`);
    } else {
        // 8초 미만: 일반 (요약 자막)
        segments.push({
            videoUrl, audioUrl,
            sceneDuration: dur,
            audioDuration: dur,
            audioStart: 0,
            needsPad: false,
            subtitleText: subText,
            type: 'normal'
        });

        if (dur > MAX_SLOW_SECONDS) {
            console.log(`Part ${i+1}: dur=${dur.toFixed(1)}s, LOOP`);
        } else {
            const slow = Math.max(1, dur / SCENE_DURATION);
            console.log(`Part ${i+1}: dur=${dur.toFixed(1)}s, slow=${slow.toFixed(2)}x`);
        }
    }
}

// === inputs 구성 ===
const inputs = [];
const segMeta = [];

for (const seg of segments) {
    const vIdx = inputs.length;
    inputs.push({ file_url: seg.videoUrl, options: [] });
    const aIdx = inputs.length;
    inputs.push({ file_url: seg.audioUrl, options: [] });
    segMeta.push({ vIdx, aIdx });
}

if (bgmUrl) {
    inputs.push({ file_url: bgmUrl, options: [{ option: "-stream_loop" }, { option: "-1" }] });
}
inputs.push({ file_url: OUTRO_URL, options: [] });
const outroIdx = inputs.length - 1;

// === filter_complex 구성 ===
let filters = [];
let subtitleData = [];
let currentTime = 0;

for (let i = 0; i < segments.length; i++) {
    const seg = segments[i];
    const { vIdx, aIdx } = segMeta[i];
    const dur = seg.sceneDuration;
    const slowFactor = Math.max(1, dur / SCENE_DURATION);

    // 비디오 필터
    // Ken Burns for split segments (avoid repetition)
    if (seg.type === 'split') {
        const KB = 1.12;
        const kbW = Math.round(1080 * KB);
        const kbH = Math.round(1920 * KB);
        const dx = kbW - 1080;
        const dy = kbH - 1920;
        const dxH = Math.round(dx / 2);
        const dyH = Math.round(dy / 2);
        const kbVariants = [
            `scale=${kbW}:${kbH},crop=1080:1920:${dxH}*t/${dur.toFixed(2)}:${dyH}*t/${dur.toFixed(2)}`,
            `scale=${kbW}:${kbH},crop=1080:1920:${dx}-${dx}*t/${dur.toFixed(2)}:${dy}-${dy}*t/${dur.toFixed(2)}`,
            `scale=${kbW}:${kbH},crop=1080:1920:${dx}*t/${dur.toFixed(2)}:${dyH}`,
            `scale=${kbW}:${kbH},crop=1080:1920:${dx}-${dx}*t/${dur.toFixed(2)}:${dyH}`,
        ];
        const kbEffect = kbVariants[seg.splitIndex % kbVariants.length];
        filters.push(`[${vIdx}:v]scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2,${kbEffect},trim=duration=${dur.toFixed(2)},setpts=PTS-STARTPTS,fps=24[v${i}]`);
    } else if (dur > MAX_SLOW_SECONDS) {
        // 루프 재생
        inputs[vIdx].options = [{ option: "-stream_loop" }, { option: "-1" }];
        filters.push(`[${vIdx}:v]scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2,trim=duration=${dur.toFixed(2)},setpts=PTS-STARTPTS,fps=24[v${i}]`);
    } else if (slowFactor > 1.01) {
        // 슬로우모션
        filters.push(`[${vIdx}:v]scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2,setpts=PTS*${slowFactor.toFixed(2)},tpad=stop_mode=clone:stop_duration=10,trim=duration=${dur.toFixed(2)},setpts=PTS-STARTPTS,fps=24[v${i}]`);
    } else {
        // 원래 속도 (5초 장면)
        filters.push(`[${vIdx}:v]scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2,trim=duration=${dur.toFixed(2)},setpts=PTS-STARTPTS,fps=24[v${i}]`);
    }

    // 오디오 필터 (패딩 필요 시 apad로 무음 채움)
    if (seg.audioStart > 0) {
        if (seg.needsPad) {
            filters.push(`[${aIdx}:a]atrim=start=${seg.audioStart.toFixed(2)}:duration=${seg.audioDuration.toFixed(2)},apad=whole_dur=${dur.toFixed(2)},asetpts=PTS-STARTPTS[a${i}]`);
        } else {
            filters.push(`[${aIdx}:a]atrim=start=${seg.audioStart.toFixed(2)}:duration=${dur.toFixed(2)},asetpts=PTS-STARTPTS[a${i}]`);
        }
    } else {
        if (seg.needsPad) {
            filters.push(`[${aIdx}:a]atrim=duration=${seg.audioDuration.toFixed(2)},apad=whole_dur=${dur.toFixed(2)},asetpts=PTS-STARTPTS[a${i}]`);
        } else {
            filters.push(`[${aIdx}:a]atrim=duration=${dur.toFixed(2)},asetpts=PTS-STARTPTS[a${i}]`);
        }
    }

    subtitleData.push({
        text: seg.subtitleText,
        start: currentTime,
        end: currentTime + dur,
    });
    currentTime += dur;
}

// 아웃트로
filters.push(`[${outroIdx}:v]scale=1080:2160,crop=1080:1920:0:0,trim=duration=${OUTRO_DURATION},setpts=PTS-STARTPTS,fps=24[voutro]`);
filters.push(`anullsrc=r=44100:cl=mono,atrim=duration=${OUTRO_DURATION}[aoutro]`);

// Fade transitions (concat 방식 - 싱크 보장)
const FADE_DUR = 0.3;
for (let k = 0; k < segments.length; k++) {
    const d = segments[k].sceneDuration;
    const vFadeIn = k > 0 ? `fade=t=in:d=${FADE_DUR},` : '';
    const vFadeOut = `fade=t=out:st=${Math.max(0, d - FADE_DUR).toFixed(2)}:d=${FADE_DUR}`;
    filters.push(`[v${k}]${vFadeIn}${vFadeOut}[vf${k}]`);
    const aFadeIn = k > 0 ? `afade=t=in:d=${FADE_DUR},` : '';
    const aFadeOut = `afade=t=out:st=${Math.max(0, d - FADE_DUR).toFixed(2)}:d=${FADE_DUR}`;
    filters.push(`[a${k}]${aFadeIn}${aFadeOut}[af${k}]`);
}
filters.push(`[voutro]fade=t=in:d=${FADE_DUR}[vfoutro]`);
filters.push(`[aoutro]acopy[afoutro]`);
let concatInputs = '';
for (let k = 0; k < segments.length; k++) {
    concatInputs += `[vf${k}][af${k}]`;
}
concatInputs += '[vfoutro][afoutro]';
filters.push(`${concatInputs}concat=n=${segments.length + 1}:v=1:a=1[outv][outa]`);

if (bgmUrl) {
    const bgmIdx = segments.length * 2;
    filters.push(`[${bgmIdx}:a]volume=0.10[bgm]`);
    filters.push(`[outa][bgm]amix=inputs=2:duration=first:dropout_transition=2[finala]`);
}

const filterComplex = filters.join('; ');
const audioMap = bgmUrl ? '[finala]' : '[outa]';

const outputOptions = [
    { option: "-filter_complex" }, { option: filterComplex },
    { option: "-map" }, { option: "[outv]" },
    { option: "-map" }, { option: audioMap },
    { option: "-c:v" }, { option: "libx264" },
    { option: "-preset" }, { option: "fast" },
    { option: "-crf" }, { option: "23" },
    { option: "-c:a" }, { option: "aac" },
    { option: "-b:a" }, { option: "192k" },
    { option: "-pix_fmt" }, { option: "yuv420p" },
    { option: "-movflags" }, { option: "+faststart" },
];

console.log(`Total segments: ${segments.length} (from ${partCount} parts), Duration: ${currentTime.toFixed(1)}s + ${OUTRO_DURATION}s outro`);

return [{
    json: {
        nca_payload: {
            inputs: inputs,
            outputs: [{ options: outputOptions }],
            global_options: [],
        },
        subtitle_data: subtitleData,
        part_count: partCount,
        segment_count: segments.length,
        has_bgm: !!bgmUrl,
        total_duration: currentTime + OUTRO_DURATION,
    }
}];

// 최종 결과 정리
const result = $input.first().json;

let videoUrl = '';
if (Array.isArray(result.response)) {
    videoUrl = result.response[0]?.file_url || '';
} else if (typeof result.response === 'string') {
    videoUrl = result.response;
} else {
    videoUrl = result.output_url || result.url || result.video_url || '';
}

// fallback
if (!videoUrl) {
    try {
        videoUrl = $('NCA 제작 결과').first().json.video_url;
    } catch(e) {}
}

console.log('Final video:', videoUrl);

return [{
    json: {
        video_url: videoUrl,
        has_caption: !!videoUrl,
    }
}];

// NCA 제작 결과 + ASS 자막 파일 생성 & MinIO 업로드
const result = $input.first().json;
const prevData = $('NCA 데이터 준비').first().json;

let videoUrl = '';
if (Array.isArray(result.response)) {
    videoUrl = result.response[0]?.file_url || '';
} else if (typeof result.response === 'string') {
    videoUrl = result.response;
} else {
    videoUrl = result.output_url || result.url || result.video_url || '';
}

console.log('Video URL:', videoUrl);

if (!videoUrl) {
    throw new Error('영상 제작 실패: ' + JSON.stringify(result).substring(0, 200));
}

// ASS 자막 파일 생성 - 나눔명조 + 아래→위 슬라이드 효과
const subtitleData = prevData.subtitle_data || [];

const RES_X = 1080;
const RES_Y = 1920;
const FINAL_Y = RES_Y - 200;
const START_Y = RES_Y + 60;
const SLIDE_DURATION_MS = 300;

let assContent = `[Script Info]
Title: Lumix Subtitle
ScriptType: v4.00+
WrapStyle: 0
PlayResX: ${RES_X}
PlayResY: ${RES_Y}

[V4+ Styles]
Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding
Style: Default,NanumGothicBold,64,&H00FFFFFF,&H000000FF,&H00000000,&H80000000,1,0,0,0,100,100,0,0,1,4,1,2,40,40,120,1

[Events]
Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text
`;

for (const sub of subtitleData) {
    if (!sub.text) continue;
    const startH = Math.floor(sub.start / 3600);
    const startM = Math.floor((sub.start % 3600) / 60);
    const startS = sub.start % 60;
    const endH = Math.floor(sub.end / 3600);
    const endM = Math.floor((sub.end % 3600) / 60);
    const endS = sub.end % 60;

    const fmt = (h, m, s) => `${h}:${String(m).padStart(2,'0')}:${s.toFixed(2).padStart(5,'0')}`;

    const centerX = Math.round(RES_X / 2);
    const moveTag = `{\\an2\\move(${centerX},${START_Y},${centerX},${FINAL_Y},0,${SLIDE_DURATION_MS})\\fad(0,200)}`;

    assContent += `Dialogue: 0,${fmt(startH,startM,startS)},${fmt(endH,endM,endS)},Default,,0,0,0,,${moveTag}${sub.text}\n`;
}

console.log('ASS content length:', assContent.length);
console.log('Subtitle entries:', subtitleData.filter(s => s.text).length);

const jobId = result.job_id || Date.now().toString();
const assFileName = `subtitles/sub_${jobId}.ass`;
const assUrl = `http://76.13.182.180:9000/nca-toolkit/${assFileName}`;

try {
    const uploadResp = await this.helpers.httpRequest({
        method: 'PUT',
        url: assUrl,
        headers: { 'Content-Type': 'text/plain; charset=utf-8' },
        body: assContent,
        returnFullResponse: true,
    });
    console.log('ASS upload status:', uploadResp.statusCode);
} catch (e) {
    console.log('ASS upload error:', e.message);
    throw new Error('ASS MinIO upload failed: ' + e.message);
}

return [{
    json: {
        video_url: videoUrl,
        ass_url: assUrl,
        has_subtitles: subtitleData.filter(s => s.text).length > 0,
    }
}];

// MIME 타입을 video/mp4로 수정 (모든 가능한 속성 덮어쓰기)
const items = $input.all();
for (const item of items) {
  if (item.binary) {
    for (const key of Object.keys(item.binary)) {
      item.binary[key].mimeType = 'video/mp4';
      item.binary[key].contentType = 'video/mp4';
      item.binary[key].fileName = 'lumix_shorts.mp4';
      item.binary[key].fileExtension = 'mp4';
    }
  }
}
return items;

