const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let videoUrl = '';

  if (data.data && data.data.resultJson) {
    try {
      const result = JSON.parse(data.data.resultJson);
      videoUrl = result.resultUrls ? result.resultUrls[0] : '';
    } catch(e) { videoUrl = ''; }
  }

  results.push({ json: { video: { url: videoUrl }, state: data.data?.state || 'unknown' } });
}

return results;

const text = $input.first().json.content.parts[0].text;
const cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const data = JSON.parse(cleanText);

const total = data.total || (
  (data.hook_power || 0) + (data.topic_relevance || 0) +
  (data.narration_quality || 0) + (data.click_appeal || 0) +
  (data.target_fit || 0) + (data.differentiation || 0)
);
const pass = total >= 42;

return [{
  json: {
    hook_power: data.hook_power || 0,
    topic_relevance: data.topic_relevance || 0,
    narration_quality: data.narration_quality || 0,
